/// `idx ∈ [0, m)`, `m ∈ {128, 512}`. The baked table is `M = 512`;
/// the `m = 128` tier reads index `t = 4 · idx` (`512 / m`). Each
/// slot stores the FRACTIONAL part `F_t = exp(t·ln2/512) − 1` as
/// `slot = round(F_t · 2^B)` (B = EXP_TANG_B, MS-limb first); the
/// integer `1` is re-added here as `10^w`. We SLICE the high-order
/// `p` limbs needed for this working scale — `slot_hi = floor(slot /
/// 2^(B − 64·p))`, the binary fixed-point of `F_t` at exponent `bp =
/// 64·p` — then reconstruct
///
/// ```text
/// round(exp(t·ln2/512) · 10^w) = 10^w + round(F_t · 10^w)
///                             = 10^w + round(slot_hi · 10^w / 2^bp)
///                             = 10^w + ((slot_hi · 10^w + 2^(bp-1)) >> bp)
/// ```
///
/// entirely in `W`: one zero-extend, one multiply, one add, one
/// shift, one add of `10^w`. `p` is chosen so `bp` carries the
/// working scale's bits plus generous guard, and so the product
/// `slot_hi · 10^w` fits `W`. `pow10_w` is `10^w` supplied by the
/// caller (the kernel's cached `pow10_table(w)` lookup), NOT a
/// per-call `W::TEN.pow(w)` recompute.
///
/// `idx = 0` short-circuits to `10^w` (exp 0 = 1). The MS-limb-first
/// layout makes the slice a contiguous high-limb PREFIX: a narrow
/// tier reads fewer limbs, the widest tier reads the whole entry.
#[inline]
pub(crate) fn exp_table_entry_baked<W: BigInt>(w: u32, idx: usize, m: u32, pow10_w: W) -> W {
    // exp(0) = 1.
    if idx == 0 {
        return pow10_w;
    }
    // Map the kernel index onto the M = 512 lattice. m ∈ {128, 512}
    // both divide 512 exactly, so `512 / m ∈ {4, 1}` and `t` is exact.
    let t = idx * (EXP_TANG_M / m) as usize;
    let slot = &EXP_TANG_SLOTS[t];
    // Binary precision needed: w·log2(10) value bits + guard. Use the
    // rational 3322/1000 ≈ log2(10) (a slight over-estimate) and a
    // 64-bit (one-limb) guard so the converted slot rounds correctly
    // yet the conversion product `slot_hi · 10^w` (≈ bp + w·log2(10)
    // ≈ 2·w·log2(10) + 64) stays inside `W`. The stored slot is a
    // pure fraction (< 1), identical to the ln pilot, so this sizing
    // is the same. Round the limb count up; clamp to the stored
    // width.
    let need_bits = (w as u64) * 3322 / 1000 + 64;
    let mut p = ((need_bits + 63) / 64) as usize;
    if p < 1 {
        p = 1;
    }
    if p > EXP_TANG_LIMBS {
        p = EXP_TANG_LIMBS;
    }
    // Zero-extend the top `p` limbs (MS-first) into W:
    //   slot_hi = sum_{k=0..p-1} slot[k] · 2^(64·(p−1−k)).
    let mut slot_hi = W::ZERO;
    for k in 0..p {
        slot_hi = (slot_hi << 64)
            | W::from_mag_sign_u128(&[slot[k] as u128], false);
    }
    let bp = (64 * p) as u32;
    let scaled = slot_hi * pow10_w;
    // Round-half-up the fractional part: add 2^(bp−1), then shift
    // right by bp; finally re-add the integer 1 (= 10^w).
    let bias = W::ONE << (bp - 1);
    pow10_w + ((scaled + bias) >> bp)
}

